"""Light smoke test for the golden-fixture set generated by
tools/generate_fixtures.py: every fixture file must exist, load with
np.load(), and contain the keys the generator promises. This is deliberately
*not* a correctness test (it needs no madmom_infer port code to exist yet) --
its only job is to catch a broken/partial/corrupted fixture set early, before
any port's own golden-fixture tests try to load these files and get a
confusing failure instead.

Reads: tests/fixtures/*.npz, tests/fixtures/manifest.json (written by
tools/generate_fixtures.py); read by: pytest
"""

import json
from pathlib import Path

import numpy as np
import pytest

